SELECT ds.student_id, ds.student_name, ds.user_id, ds.driver_license_id, ds.phone, emergency_phone, ds.status, ds.id_number, id_number_front, id_number_back, ds.create_time, avatar, student_code,ddlt.driver_license_code, dcr.finished_hours,dcr.status,di.instructor_name,di.score,dsj.subject_name FROM ms_stu_pro339.driving_student ds LEFT JOIN ms_stu_pro339.driving_driver_license_type ddlt ON ds.driver_license_id = ddlt.driver_license_id LEFT JOIN ms_stu_pro339.driving_course_record dcr ON dcr.record_id = ds.student_id LEFT JOIN ms_stu_pro339.driving_instructor_student dis ON dis.student_id = ds.student_id LEFT JOIN ms_stu_pro339.driving_subject dsj ON dis.subject_id = dsj.subject_id LEFT JOIN ms_stu_pro339.driving_instructor di ON dis.instructor_id = di.instructor_id
AND ds.student_name LIKE CONCAT('%',#{drivingStudentQuery.studentName},'%')
AND ds.phone =#{drivingStudentQuery.phone}
AND ds.id_number = #{drivingStudentQuery.idNumber}
ORDER BY student_id ASC
